code = """import json
# Load purchases with perfect avg rating
purchases = var_call_PPhyewW6gF9Kd7Iml5qmcTr5
# Load books info from JSON file path
books_file = var_call_XBi2V0cBq2PQ4pNYgXDkwWJP
with open(books_file, 'r', encoding='utf-8') as f:
    books = json.load(f)

# Build set of book_ids corresponding to purchase_ids by replacing prefix
purchase_ids = [rec.get('purchase_id') for rec in purchases]
book_ids_set = set()
for pid in purchase_ids:
    if pid is None:
        continue
    # replace common prefixes
    bid = pid.replace('purchaseid_', 'bookid_')
    book_ids_set.add(bid)

results = []
for b in books:
    bid = b.get('book_id')
    if bid not in book_ids_set:
        continue
    # parse categories which are stored as a JSON-like string
    cats_raw = b.get('categories') or '[]'
    try:
        cats = json.loads(cats_raw)
    except Exception:
        # fallback: simple split
        cats = []
        for part in cats_raw.replace('[','').replace(']','').split(','):
            part = part.strip().strip('"').strip('\'')
            if part:
                cats.append(part)
    cats_lower = [c.lower() for c in cats if isinstance(c, str)]
    if 'literature & fiction' not in cats_lower and 'literature and fiction' not in cats_lower:
        continue
    # check details or description for English language
    details = (b.get('details') or '').lower()
    description = (b.get('description') or '').lower()
    is_english = False
    if 'english' in details or 'english' in description:
        is_english = True
    # also check for patterns
    if not is_english:
        # look for 'written in english' phrase
        if 'written in english' in details or 'written in english' in description:
            is_english = True
    if not is_english:
        continue
    # include relevant fields
    results.append({
        'book_id': bid,
        'title': b.get('title'),
        'author': b.get('author'),
        'categories': cats,
        'details': b.get('details')
    })

# Print result in required format as JSON string
print("__RESULT__:")
print(json.dumps(results))"""

